import{_ as t,o as a,c as s,a2 as i}from"./chunks/framework.D5wUhsuj.js";const o="/docs/assets/api-key-list.9UOAgdbp.png",n="/docs/assets/create-key-ui.qZM1YoFm.png",r="/docs/assets/api-key-shown-once.C6831IG6.png",l="/docs/assets/api-key-edit-disable-rotate-menu.DJuQiyzy.png",m=JSON.parse('{"title":"API Keys","description":"","frontmatter":{},"headers":[],"relativePath":"platform/api_keys.md","filePath":"platform/api_keys.md","lastUpdated":1783543014000}'),h={name:"platform/api_keys.md"};function d(c,e,p,u,y,k){return a(),s("div",null,[...e[0]||(e[0]=[i('<h1 id="api-keys" tabindex="-1">API Keys <a class="header-anchor" href="#api-keys" aria-label="Permalink to &quot;API Keys&quot;">​</a></h1><p>API keys provide scoped programmatic access to selected prokube services without a browser session. Use them for SDKs, automation, CI jobs, serving clients, sandbox clients, MCP clients, and external integrations.</p><p>A key belongs to the workspace that was selected when it was created. prokube routes public API traffic through <a href="./../agentops/agent_gateway.html">Agent Gateway</a>, the shared routing and policy layer for API clients, but you do not need to configure Agent Gateway to create a key.</p><p>Use API keys when a workload or external client needs repeatable access without an interactive login. For browser-based work in the prokube UI, use your normal user session instead.</p><h2 id="manage-keys-in-the-ui" tabindex="-1">Manage Keys in the UI <a class="header-anchor" href="#manage-keys-in-the-ui" aria-label="Permalink to &quot;Manage Keys in the UI&quot;">​</a></h2><p>Open <strong>API Keys</strong> from the sidebar under <strong>Serving</strong>. Select the workspace before creating or editing keys.</p><p>Regular users see only their own keys in the selected workspace. Administrators can see and manage all keys in the workspace.</p><p><img src="'+o+'" alt="API Keys list with filters and key metadata" loading="lazy"></p><p>The table shows key metadata, not the full key value.</p><p>Visible metadata includes the key name, prefix, owner, status, expiration, authentication format, and scope summary. The prefix helps identify which key a client is using without exposing the secret value.</p><h2 id="ownership-and-workspace-scope" tabindex="-1">Ownership and Workspace Scope <a class="header-anchor" href="#ownership-and-workspace-scope" aria-label="Permalink to &quot;Ownership and Workspace Scope&quot;">​</a></h2><p>API keys are scoped by both workspace and owner:</p><ul><li>A key can only grant access inside the workspace where it was created.</li><li>Regular users can list, edit, rotate, disable, and delete only their own keys.</li><li>Administrators can list and manage all keys in the selected workspace.</li></ul><p>For shared automation, avoid personal long-lived keys where possible. Prefer a key created by the user or service account that owns the automation, and document where the secret is stored.</p><h2 id="create-a-key" tabindex="-1">Create a Key <a class="header-anchor" href="#create-a-key" aria-label="Permalink to &quot;Create a Key&quot;">​</a></h2><p>Click <strong>Create Key</strong> and fill in the form:</p><ul><li><strong>Name</strong>: a descriptive name for the key.</li><li><strong>Description</strong>: optional context for who or what uses the key.</li><li><strong>Expiration Date</strong>: optional. Use expirations for automation keys unless there is a clear rotation process.</li><li><strong>Client Authentication</strong>: choose how clients send the key.</li><li><strong>Select Services</strong>: choose the services this key may access.</li></ul><p><img src="'+n+`" alt="Create API Key dialog with client authentication and service selection" loading="lazy"></p><p>The service list is built from services available in the selected workspace. It can include:</p><ul><li><strong>Models</strong> for KServe and LLM endpoints.</li><li><strong>Sandbox API</strong> for Agent Sandbox programmatic access.</li><li><strong>MCP servers</strong> for tool access.</li><li><strong>Memory stores</strong> exposed through MCP-compatible routes.</li><li><strong>A2A agents</strong> for kagent agent-to-agent access.</li><li><strong>Knative services</strong> exposed through gateway routes.</li></ul><p>Select only the services the client needs. If no services are available, deploy or expose the service first, then create the key.</p><p>Service-specific scopes are the default choice for production clients. They reduce blast radius if a key is exposed and make it clear which integration depends on which platform service.</p><h2 id="client-authentication" tabindex="-1">Client Authentication <a class="header-anchor" href="#client-authentication" aria-label="Permalink to &quot;Client Authentication&quot;">​</a></h2><p>Choose the authentication format expected by the client:</p><table tabindex="0"><thead><tr><th>Format</th><th>Use when</th></tr></thead><tbody><tr><td><code>Authorization: Bearer &lt;key&gt;</code></td><td>The client is OpenAI-compatible or expects bearer authentication. This is the recommended format for LLM clients.</td></tr><tr><td><code>x-api-key: &lt;key&gt;</code></td><td>The client uses existing prokube service examples for Sandboxes, MCP, A2A, or other non-OpenAI-style APIs.</td></tr></tbody></table><p>Use the service page for the exact URL and request body. Examples:</p><p>Sandbox-style APIs commonly use <code>x-api-key</code>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;https://&lt;your-prokube-domain&gt;/sandbox/&lt;workspace&gt;/sandboxes&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;x-api-key: &lt;api-key&gt;&quot;</span></span></code></pre></div><p>OpenAI-compatible model clients commonly use bearer authentication:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;https://&lt;your-prokube-domain&gt;/ai/&lt;workspace&gt;/v1/chat/completions&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Authorization: Bearer &lt;api-key&gt;&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Content-Type: application/json&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;{&quot;model&quot;:&quot;&lt;model&gt;&quot;,&quot;messages&quot;:[{&quot;role&quot;:&quot;user&quot;,&quot;content&quot;:&quot;Hello&quot;}]}&#39;</span></span></code></pre></div><h2 id="copy-the-key-value" tabindex="-1">Copy the Key Value <a class="header-anchor" href="#copy-the-key-value" aria-label="Permalink to &quot;Copy the Key Value&quot;">​</a></h2><p>prokube shows the full key value only after creation or rotation. Copy it immediately and store it in your secret manager.</p><p>If you close the dialog without copying the key, create a new key or rotate the existing key. The old full value cannot be recovered from the UI.</p><p><img src="`+r+'" alt="One-time API key display with copy action and client example" loading="lazy"></p><h2 id="manage-existing-keys" tabindex="-1">Manage Existing Keys <a class="header-anchor" href="#manage-existing-keys" aria-label="Permalink to &quot;Manage Existing Keys&quot;">​</a></h2><p>From the API Keys page you can:</p><ul><li>search keys by name or prefix;</li><li>filter by status, expiration, and scope type;</li><li>edit metadata, expiration, enabled state, and service scopes;</li><li>disable, rotate, or delete keys.</li></ul><p>Disable a key when you need temporary revocation or want to test whether a client still depends on it. Delete a key when it is no longer needed.</p><p>Rotating a key invalidates the old value immediately. Update every client or secret that uses the key before relying on the rotated value.</p><img src="'+l+'" alt="API key action menu with edit, disable, rotate, and delete actions" style="max-width:360px;width:100%;height:auto;"><h2 id="security-guidance" tabindex="-1">Security Guidance <a class="header-anchor" href="#security-guidance" aria-label="Permalink to &quot;Security Guidance&quot;">​</a></h2><ul><li>Prefer service-specific keys over broad workspace access.</li><li>Set an expiration date for automation keys where possible.</li><li>Store keys in a secret manager, not in source code, notebooks, screenshots, shell history, or issues.</li><li>Rotate keys when ownership changes, a client is redeployed, or a key may have been exposed.</li><li>Disable a key first if you need to test impact before deleting it.</li><li>Delete keys that are no longer used.</li></ul><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Symptom</th><th>Check</th></tr></thead><tbody><tr><td>No services are available when creating a key</td><td>Confirm the target service exists in the selected workspace and is exposed through Agent Gateway-supported routes.</td></tr><tr><td>A key is not visible to another user in the same workspace</td><td>Regular users only see keys they created. Ask an administrator if shared visibility or management is required.</td></tr><tr><td>Client receives <code>401</code> or <code>403</code></td><td>Confirm the key is enabled, not expired, sent with the selected authentication header, and scoped to the target service.</td></tr><tr><td>Client can call one service but not another</td><td>The key is scoped to selected services. Edit the key or create a new key for the additional service.</td></tr><tr><td>Client stopped working after rotation</td><td>The old key value stopped working immediately. Update the client secret or environment variable with the new value.</td></tr></tbody></table><h2 id="related-pages" tabindex="-1">Related Pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related Pages&quot;">​</a></h2><ul><li><a href="./../agentops/sandboxes.html">Sandboxes</a></li><li><a href="./../agentops/mcp_servers.html">MCP Servers</a></li><li><a href="./../mlops/model_serving.html">Model Serving</a></li><li><a href="./../mlops/knative.html">Serverless</a></li></ul>',46)])])}const b=t(h,[["render",d]]);export{m as __pageData,b as default};
